sp_widget.client_script:
api.controller = function ($scope) {
    // ── DOM references ────────────────────────────────────────────────────────
    var tableInput        = document.getElementById('tableInput');
    var queryInput        = document.getElementById('queryInput');
    var datefieldInput    = document.getElementById('datefieldInput');
    var confidenceInput   = document.getElementById('confidenceInput');
    var iterationsInput   = document.getElementById('iterationsInput');
    var daysInput         = document.getElementById('daysInput');
    var tasksInput        = document.getElementById('tasksInput');
    var runButton         = document.getElementById('runButton');
    var daysLabel         = document.getElementById('daysLabel');
    var tasksLabel        = document.getElementById('tasksLabel');
    var tasksLabelCone    = document.getElementById('tasksLabelCone');
    var throughputDisplay = document.getElementById('throughputConfidenceDisplay');
    var completionDisplay = document.getElementById('completionConfidenceDisplay');

    if (!runButton) { console.error("Widget elements not found."); return; }

    // ── State ─────────────────────────────────────────────────────────────────
    var confidenceValue    = 85;
    var daysValue          = 14;
    var tasksValue         = 50;
    var throughputData     = $scope.data.throughputHistogramData || [];
    var completionData     = $scope.data.completionHistogramData || [];
    var throughputConeData = $scope.data.throughputConeData      || null;
    var completionConeData = $scope.data.completionConeData      || null;

    var chartThroughput     = null;
    var chartCompletion     = null;
    var chartThroughputCone = null;
    var chartCompletionCone = null;

    // ── Percentile helpers ────────────────────────────────────────────────────
    // Throughput: right-to-left (at least X tasks with confidence%)
    function throughputPercentile(histData, confidence) {
        var total = histData.reduce(function (s, d) { return s + d.frequency; }, 0);
        var cum = 0;
        for (var i = histData.length - 1; i >= 0; i--) {
            cum += histData[i].frequency;
            if (cum / total >= confidence / 100) { return histData[i].throughput; }
        }
        return histData[0] ? histData[0].throughput : 0;
    }

    // Completion: left-to-right (finish within X days with confidence%)
    function completionPercentile(histData, confidence) {
        var total = histData.reduce(function (s, d) { return s + d.frequency; }, 0);
        var cum = 0;
        for (var i = 0; i < histData.length; i++) {
            cum += histData[i].frequency;
            if (cum / total >= confidence / 100) { return histData[i].days; }
        }
        return histData[histData.length - 1] ? histData[histData.length - 1].days : 0;
    }

    // ── Histogram renderers ───────────────────────────────────────────────────
    function renderThroughputChart(histData, confidence) {
        histData.sort(function (a, b) { return a.throughput - b.throughput; });
        var pct = throughputPercentile(histData, confidence);
        throughputDisplay.textContent = confidence + '% (' + pct + ' tasks)';
        if (chartThroughput) { chartThroughput.destroy(); }
        chartThroughput = new Chart(
            document.getElementById('throughputChart').getContext('2d'), {
            type: 'bar',
            data: {
                labels: histData.map(function (d) { return d.throughput; }),
                datasets: [{
                    label: 'Occurrences',
                    data: histData.map(function (d) { return d.frequency; }),
                    backgroundColor: 'rgba(75,192,192,0.2)',
                    borderColor:     'rgba(75,192,192,1)',
                    borderWidth: 1, barPercentage: 1.0, categoryPercentage: 1.0
                }]
            },
            options: {
                plugins: { annotation: { annotations: { cl: {
                    type: 'line', xMin: pct, xMax: pct,
                    borderColor: 'red', borderWidth: 2,
                    label: { content: String(pct), enabled: true, position: 'start',
                             backgroundColor: 'rgba(255,99,132,0.85)', color: 'white',
                             font: { size: 12, weight: 'bold' }, padding: 6 }
                }}}},
                scales: {
                    x: { type: 'linear', title: { display: true, text: 'Number of Tasks' } },
                    y: { beginAtZero: true, title: { display: true, text: 'Frequency' } }
                }
            }
        });
        return pct;
    }

    function renderCompletionChart(histData, confidence) {
        histData.sort(function (a, b) { return a.days - b.days; });
        var pct = completionPercentile(histData, confidence);
        completionDisplay.textContent = confidence + '% (' + pct + ' days)';
        if (chartCompletion) { chartCompletion.destroy(); }
        chartCompletion = new Chart(
            document.getElementById('completionChart').getContext('2d'), {
            type: 'bar',
            data: {
                labels: histData.map(function (d) { return d.days; }),
                datasets: [{
                    label: 'Occurrences',
                    data: histData.map(function (d) { return d.frequency; }),
                    backgroundColor: 'rgba(153,102,255,0.2)',
                    borderColor:     'rgba(153,102,255,1)',
                    borderWidth: 1, barPercentage: 1.0, categoryPercentage: 1.0
                }]
            },
            options: {
                plugins: { annotation: { annotations: { cl: {
                    type: 'line', xMin: pct, xMax: pct,
                    borderColor: 'red', borderWidth: 2,
                    label: { content: String(pct), enabled: true, position: 'start',
                             backgroundColor: 'rgba(255,99,132,0.85)', color: 'white',
                             font: { size: 12, weight: 'bold' }, padding: 6 }
                }}}},
                scales: {
                    x: { type: 'linear', title: { display: true, text: 'Number of Days' } },
                    y: { beginAtZero: true, title: { display: true, text: 'Frequency' } }
                }
            }
        });
        return pct;
    }

    // ── Cone of Uncertainty renderers ─────────────────────────────────────────
    function coneDatasets(cd, r, g, b) {
        // Dataset ordering: p10, p90, p25, p75, p50
        // fill: '+1' on p10 → fills up to p90 (outer band)
        // fill: '+1' on p25 → fills up to p75 (inner band)
        function pts(arr) {
            return cd.days.map(function (d, i) { return { x: d, y: arr[i] }; });
        }
        var co = 'rgba(' + r + ',' + g + ',' + b + ',';
        return [
            { label: '10th\u201390th %ile', data: pts(cd.p10),
              borderColor: co + '0.25)', borderWidth: 1, pointRadius: 0,
              fill: '+1', backgroundColor: co + '0.07)' },
            { label: '', data: pts(cd.p90),
              borderColor: co + '0.25)', borderWidth: 1, pointRadius: 0, fill: false },
            { label: '25th\u201375th %ile', data: pts(cd.p25),
              borderColor: co + '0.45)', borderWidth: 1, pointRadius: 0,
              fill: '+1', backgroundColor: co + '0.15)' },
            { label: '', data: pts(cd.p75),
              borderColor: co + '0.45)', borderWidth: 1, pointRadius: 0, fill: false },
            { label: '50th %ile (median)', data: pts(cd.p50),
              borderColor: co + '1)', borderWidth: 2, pointRadius: 0, fill: false }
        ];
    }

    function coneOptions(xTitle, yTitle, annotations) {
        return {
            plugins: {
                legend: {
                    display: true,
                    labels: { filter: function (item) { return item.text !== ''; } }
                },
                annotation: { annotations: annotations }
            },
            scales: {
                x: { type: 'linear', title: { display: true, text: xTitle } },
                y: { beginAtZero: true, title: { display: true, text: yTitle } }
            }
        };
    }

    function renderThroughputCone(coneData, confidence, pctTasks) {
        if (!coneData || !coneData.days || coneData.days.length === 0) { return; }
        var datasets = coneDatasets(coneData, 75, 192, 192);
        var annotations = {};
        if (pctTasks !== null) {
            annotations.cl = {
                type: 'line', yMin: pctTasks, yMax: pctTasks,
                borderColor: 'red', borderWidth: 1.5, borderDash: [5, 4],
                label: { content: confidence + '% \u2265 ' + pctTasks,
                         enabled: true, position: 'end',
                         backgroundColor: 'rgba(255,99,132,0.85)', color: 'white',
                         font: { size: 11, weight: 'bold' }, padding: 5 }
            };
        }
        if (chartThroughputCone) { chartThroughputCone.destroy(); }
        chartThroughputCone = new Chart(
            document.getElementById('throughputConeChart').getContext('2d'),
            { type: 'line', data: { datasets: datasets },
              options: coneOptions('Day', 'Cumulative Tasks', annotations) }
        );
    }

    function renderCompletionCone(coneData, tasks, confidence, pctDays) {
        if (!coneData || !coneData.days || coneData.days.length === 0) { return; }
        var datasets = coneDatasets(coneData, 153, 102, 255);
        // Add horizontal target line
        datasets.push({
            label: 'Target (' + tasks + ' tasks)',
            data: coneData.days.map(function (d) { return { x: d, y: tasks }; }),
            borderColor: 'rgba(255,99,132,0.9)', borderWidth: 2,
            borderDash: [6, 4], pointRadius: 0, fill: false
        });
        var annotations = {};
        if (pctDays !== null) {
            annotations.cl = {
                type: 'line', xMin: pctDays, xMax: pctDays,
                borderColor: 'red', borderWidth: 1.5, borderDash: [5, 4],
                label: { content: confidence + '% \u2264 ' + pctDays + ' d',
                         enabled: true, position: 'start',
                         backgroundColor: 'rgba(255,99,132,0.85)', color: 'white',
                         font: { size: 11, weight: 'bold' }, padding: 5 }
            };
        }
        if (chartCompletionCone) { chartCompletionCone.destroy(); }
        chartCompletionCone = new Chart(
            document.getElementById('completionConeChart').getContext('2d'),
            { type: 'line', data: { datasets: datasets },
              options: coneOptions('Day', 'Cumulative Tasks', annotations) }
        );
    }

    // ── Render all four charts ────────────────────────────────────────────────
    function renderAll() {
        var pctTasks = null;
        var pctDays  = null;
        if (throughputData.length > 0) {
            pctTasks = renderThroughputChart(throughputData, confidenceValue);
        }
        if (completionData.length > 0) {
            pctDays = renderCompletionChart(completionData, confidenceValue);
        }
        renderThroughputCone(throughputConeData, confidenceValue, pctTasks);
        renderCompletionCone(completionConeData, tasksValue, confidenceValue, pctDays);
    }

    // ── Run Simulation button ─────────────────────────────────────────────────
    runButton.addEventListener('click', function () {
        var days       = parseInt(daysInput.value, 10);
        var tasks      = parseInt(tasksInput.value, 10);
        var iterations = parseInt(iterationsInput.value, 10);
        var confidence = parseInt(confidenceInput.value, 10);

        if (isNaN(days)       || days <= 0)                          { alert("Invalid days.");        return; }
        if (isNaN(tasks)      || tasks <= 0)                         { alert("Invalid tasks.");       return; }
        if (isNaN(iterations) || iterations <= 0)                    { alert("Invalid iterations.");  return; }
        if (isNaN(confidence) || confidence < 1 || confidence > 100) { alert("Invalid confidence.");  return; }

        confidenceValue        = confidence;
        daysValue              = days;
        tasksValue             = tasks;
        daysLabel.textContent  = days;
        tasksLabel.textContent = tasks;
        tasksLabelCone.textContent = tasks;

        $scope.server.get({
            days: days, tasks: tasks, iterations: iterations,
            queryTable: tableInput.value, queryEncoded: queryInput.value,
            dateField: datefieldInput.value
        }).then(function (response) {
            throughputData     = response.data.throughputHistogramData || [];
            completionData     = response.data.completionHistogramData || [];
            throughputConeData = response.data.throughputConeData      || null;
            completionConeData = response.data.completionConeData      || null;
            tasksValue         = response.data.tasks || tasks;
            renderAll();
        });
    });

    // ── Confidence changes → re-render all charts (no new simulation needed) ──
    confidenceInput.addEventListener('input', function () {
        var value = parseInt(confidenceInput.value, 10);
        if (value >= 1 && value <= 100) {
            confidenceValue = value;
            renderAll();
        }
    });

    // ── Initial render with server-provided data ──────────────────────────────
    renderAll();
};

sp_widget.css:
.mc-header {
    background: #f4f4f4;
    border-bottom: 1px solid #ddd;
    padding: 12px 16px;
    margin-bottom: 20px;
}
.mc-header h1 {
    margin: 0 0 12px 0;
    font-size: 20px;
}
.mc-inputs {
    display: flex;
    flex-wrap: wrap;
    gap: 12px;
    align-items: flex-end;
}
.mc-inputs .mc-field {
    display: flex;
    flex-direction: column;
    gap: 4px;
}
.mc-inputs label {
    font-size: 12px;
    color: #555;
    margin: 0;
}
.mc-inputs input {
    padding: 4px 6px;
    border: 1px solid #ccc;
    border-radius: 3px;
}
.mc-inputs input[type=number] { width: 70px; }
.mc-inputs input[type=text]   { width: 130px; }
#queryInput                   { width: 200px; }
.mc-run-btn {
    padding: 6px 18px;
    background: #176BCC;
    color: white;
    border: none;
    border-radius: 3px;
    cursor: pointer;
    font-size: 14px;
    align-self: flex-end;
}
.mc-run-btn:hover { background: #1258a8; }
.mc-section-title {
    font-size: 14px;
    font-weight: bold;
    color: #444;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    border-bottom: 1px solid #ddd;
    padding-bottom: 4px;
    margin: 24px 0 12px 0;
}
.mc-charts {
    display: flex;
    gap: 20px;
    margin-bottom: 8px;
}
.mc-chart-panel {
    flex: 1;
    min-width: 0;
}
.mc-chart-panel h3 {
    font-size: 14px;
    margin: 0 0 4px 0;
}
.mc-confidence-label {
    font-size: 13px;
    color: #555;
    margin: 0 0 8px 0;
}

sp_widget.script:
(function () {
    var days         = input && input.days         ? parseInt(input.days, 10)       : 14;
    var tasks        = input && input.tasks        ? parseInt(input.tasks, 10)      : 50;
    var iterations   = input && input.iterations   ? parseInt(input.iterations, 10) : 10000;
    var queryTable   = input && input.queryTable   ? input.queryTable               : 'incident';
    var queryEncoded = input && input.queryEncoded ? input.queryEncoded             : 'active=false';
    var dateField    = input && input.dateField    ? input.dateField                : 'closed_at';

    var taskDataUtil  = new McTaskUtil();
    var monteCarloSim = new McSimUtil();

    var dailyThroughput = taskDataUtil.getDailyThroughput(queryTable, dateField, queryEncoded);
    if (dailyThroughput.length === 0) {
        data.error = "No historical data available.";
        return;
    }

    // ── Sturges-binned histogram ──────────────────────────────────────────────
    function buildHistogram(results, valueKey) {
        var sorted   = results.slice().sort(function (a, b) { return a - b; });
        var minVal   = sorted[0];
        var maxVal   = sorted[sorted.length - 1];
        var numBins  = Math.ceil(1 + Math.log(results.length) / Math.log(2));
        var binWidth = Math.max(1, Math.ceil((maxVal - minVal + 1) / numBins));

        var histogram = {};
        for (var k = 0; minVal + k * binWidth <= maxVal; k++) {
            histogram[minVal + k * binWidth] = 0;
        }
        for (var r = 0; r < results.length; r++) {
            var binKey = minVal + Math.floor((results[r] - minVal) / binWidth) * binWidth;
            histogram[binKey]++;
        }
        var histData = Object.keys(histogram).map(function (key) {
            var item = { frequency: histogram[key] };
            item[valueKey] = parseInt(key, 10);
            return item;
        });
        histData.sort(function (a, b) { return a[valueKey] - b[valueKey]; });
        return { data: histData, binWidth: binWidth };
    }

    // ── Day-by-day cone computation (one pass, O(maxDays × iterations)) ───────
    // Advances every iteration by one day at a time, extracting p10/p25/p50/p75/p90
    // after each step to build the widening bands of the cone.
    function computeCone(maxDays, iters, throughput) {
        var coneData = { days: [], p10: [], p25: [], p50: [], p75: [], p90: [] };
        var cumulative = [];
        for (var iter = 0; iter < iters; iter++) { cumulative.push(0); }

        for (var d = 1; d <= maxDays; d++) {
            coneData.days.push(d);
            for (var iter = 0; iter < iters; iter++) {
                cumulative[iter] += throughput[Math.floor(Math.random() * throughput.length)];
            }
            var sorted = cumulative.slice().sort(function (a, b) { return a - b; });
            var n = sorted.length;
            coneData.p10.push(sorted[Math.min(Math.floor(0.10 * n), n - 1)]);
            coneData.p25.push(sorted[Math.min(Math.floor(0.25 * n), n - 1)]);
            coneData.p50.push(sorted[Math.min(Math.floor(0.50 * n), n - 1)]);
            coneData.p75.push(sorted[Math.min(Math.floor(0.75 * n), n - 1)]);
            coneData.p90.push(sorted[Math.min(Math.floor(0.90 * n), n - 1)]);
        }
        return coneData;
    }

    // ── Simulation 1: Tasks in X days ────────────────────────────────────────
    var throughputResults = monteCarloSim.simulateThroughput(days, iterations, dailyThroughput);
    var throughputHist    = buildHistogram(throughputResults, 'throughput');
    data.throughputHistogramData = throughputHist.data;
    data.throughputBinWidth      = throughputHist.binWidth;
    data.throughputConeData      = computeCone(days, iterations, dailyThroughput);

    // ── Simulation 2: Days to complete X tasks ────────────────────────────────
    var completionResults = monteCarloSim.simulateDaysToComplete(tasks, iterations, dailyThroughput);
    var completionHist    = buildHistogram(completionResults, 'days');
    data.completionHistogramData = completionHist.data;
    data.completionBinWidth      = completionHist.binWidth;

    // Extend the completion cone to the 95th-percentile completion day (max 365)
    var sortedCompletion = completionResults.slice().sort(function (a, b) { return a - b; });
    var p95Days = sortedCompletion[Math.min(Math.floor(0.95 * sortedCompletion.length), sortedCompletion.length - 1)];
    data.completionConeData = computeCone(Math.min(p95Days, 365), iterations, dailyThroughput);

    data.tasks = tasks;
})();
